#!/usr/bin/env python3
"""Generate host/robot_radio/robot/pb2/*_pb2.py — compiled Python protobuf
bindings from proto3 message definitions.

Run:  python3 scripts/gen_pb2.py

Companion to scripts/gen_messages.py (095-002, M7 Host Codec Mirror). Both
scripts compile from the identical protos/*.proto source on every build
(via grpc_tools, already a codegen-group dependency) — gen_messages.py emits
the FIRMWARE's hand-rolled-free C++11 POD headers, this script emits the
HOST's compiled Python bindings — so device tables and host pb2 bindings can
never skew independently.

Unlike gen_messages.py (which parses a FileDescriptorSet itself and hand-
emits C++), this script is a thin wrapper around protoc's OWN Python
plugin (``--python_out``) — the generated ``*_pb2.py`` files are never
hand-restructured or hand-edited, matching the same "generated code" contract
source/messages/*.h already has.

Flat-import gotcha (see host/robot_radio/robot/pb2/__init__.py, written by
this script): protoc's Python codegen, run flat (-I protos, no nested output
tree), emits each *_pb2.py's cross-file references as a bare top-level
import (e.g. envelope_pb2.py contains ``import drivetrain_pb2 as
drivetrain__pb2``) rather than a relative or package-qualified import. That
statement only resolves if the pb2/ directory itself is on sys.path — the
generated __init__.py this script writes inserts it there once, at
package-import time (the standard/conventional fix for this well-known
grpc_tools.protoc flat-output limitation).
"""

import shutil
import sys
from pathlib import Path

REPO_ROOT = Path(__file__).resolve().parent.parent
PROTO_DIR = REPO_ROOT / "protos"
PB2_DIR = REPO_ROOT / "host" / "robot_radio" / "robot" / "pb2"

_INIT_PY = '''"""Compiled protobuf Python bindings for protos/*.proto (095-002, M7 Host
Codec Mirror).

GENERATED by scripts/gen_pb2.py via ``grpc_tools.protoc --python_out`` —
NEVER hand-edited (mirrors source/messages/*.h's "generated, not
hand-authored" contract on the firmware side). Re-run
``python3 scripts/gen_pb2.py`` (or ``just build``/``just build-sim``/
``python3 build.py``, which already call it) after editing any
protos/*.proto file.

Flat-import shim: protoc's Python codegen, run flat (-I protos, no nested
output tree matching this package's own dotted path), emits each
``*_pb2.py``'s cross-file references as a bare top-level import (e.g.
``envelope_pb2.py`` contains ``import drivetrain_pb2 as drivetrain__pb2``)
rather than a relative or ``robot_radio.robot.pb2``-qualified import. Such a
bare import only resolves via sys.path — Python 3 has no implicit
relative-package import — so it does NOT resolve merely because a caller
does ``from robot_radio.robot.pb2 import envelope_pb2``. Inserting this
package's own directory onto sys.path here, once, at package-import time,
is the standard/conventional fix for this well-known grpc_tools.protoc
flat-output limitation: it runs before any ``*_pb2`` submodule is imported,
since Python always imports and executes a package's __init__.py before any
of its submodules.
"""
import os
import sys

_here = os.path.dirname(os.path.abspath(__file__))
if _here not in sys.path:
    sys.path.insert(0, _here)
'''


class GenPb2Error(RuntimeError):
    """Raised on any pb2 codegen pipeline failure."""


def run_codegen() -> list[str]:
    """Run protoc --python_out over every protos/*.proto into PB2_DIR.

    Wipes and recreates PB2_DIR (generated-output contract: PB2_DIR's
    entire contents are protoc output, so a stale module left over from a
    since-deleted/renamed .proto file can never linger). Writes the
    flat-import sys.path shim __init__.py last, after protoc has run.

    Returns the sorted list of proto file names compiled. Raises
    GenPb2Error on any failure.
    """
    try:
        import grpc_tools
        from grpc_tools import protoc
    except ImportError as exc:
        raise GenPb2Error(
            "grpcio-tools is not installed.\n"
            "  Run: uv sync  (grpcio-tools is in the 'codegen' dependency group)"
        ) from exc

    well_known_dir = str(Path(grpc_tools.__file__).parent / "_proto")
    proto_names = sorted(p.name for p in PROTO_DIR.glob("*.proto"))
    proto_paths = [str(PROTO_DIR / n) for n in proto_names]
    if not proto_paths:
        raise GenPb2Error(f"no *.proto files found under {PROTO_DIR}")

    if PB2_DIR.exists():
        shutil.rmtree(PB2_DIR)
    PB2_DIR.mkdir(parents=True, exist_ok=True)

    ret = protoc.main([
        "protoc",
        "-I", str(PROTO_DIR),
        "-I", well_known_dir,
        f"--python_out={PB2_DIR}",
    ] + proto_paths)
    if ret != 0:
        raise GenPb2Error("protoc failed — check proto syntax.")

    (PB2_DIR / "__init__.py").write_text(_INIT_PY)
    return proto_names


def main(argv=None) -> int:
    try:
        proto_names = run_codegen()
    except GenPb2Error as exc:
        print(f"gen_pb2: {exc}", file=sys.stderr)
        return 1

    print(
        f"gen_pb2: wrote {len(proto_names)} pb2 module(s) to "
        f"{PB2_DIR.relative_to(REPO_ROOT)}",
        file=sys.stderr,
    )
    return 0


if __name__ == "__main__":
    sys.exit(main())
